using System.ComponentModel;
using System.Net.Http.Json;
using System.Text.Json;
using Microsoft.Extensions.AI;

namespace ResearchAgent;

/// <summary>
/// Tools available to the research agent for web searching and note-taking.
/// </summary>
public sealed class ResearchTools
{
    private static readonly HttpClient s_httpClient = new()
    {
        Timeout = TimeSpan.FromSeconds(15),
    };

    private readonly List<string> _notes = [];

    /// <summary>
    /// Creates the set of AI tools for the research agent.
    /// </summary>
    public IList<AITool> CreateTools()
    {
        return
        [
            AIFunctionFactory.Create(SearchWebAsync, name: "search_web"),
            AIFunctionFactory.Create(SaveNote, name: "save_note"),
            AIFunctionFactory.Create(GetNotes, name: "get_notes"),
        ];
    }

    /// <summary>
    /// Returns all notes saved during the research session.
    /// </summary>
    public IReadOnlyList<string> Notes => _notes.AsReadOnly();

    [Description("Searches the web for a query and returns relevant results. Use this to find information about a topic.")]
    private static async Task<string> SearchWebAsync(
        [Description("The search query to look up on the web")] string query,
        CancellationToken cancellationToken = default)
    {
        try
        {
            // Use DuckDuckGo Instant Answer API (no API key required).
            var encodedQuery = Uri.EscapeDataString(query);
            var url = $"https://api.duckduckgo.com/?q={encodedQuery}&format=json&no_html=1&skip_disambig=1";

            var response = await s_httpClient.GetFromJsonAsync<JsonElement>(url, cancellationToken);

            var results = new List<string>();

            // Extract the abstract/summary if available.
            var abstractText = response.GetProperty("Abstract").GetString();
            var abstractSource = response.GetProperty("AbstractSource").GetString();
            if (!string.IsNullOrWhiteSpace(abstractText))
            {
                results.Add($"[{abstractSource}] {abstractText}");
            }

            // Extract related topics for additional context.
            if (response.TryGetProperty("RelatedTopics", out var relatedTopics))
            {
                foreach (var topic in relatedTopics.EnumerateArray().Take(5))
                {
                    var text = topic.TryGetProperty("Text", out var t) ? t.GetString() : null;
                    if (!string.IsNullOrWhiteSpace(text))
                    {
                        results.Add(text);
                    }
                }
            }

            // Extract answer if available (for factual queries).
            var answer = response.GetProperty("Answer").GetString();
            if (!string.IsNullOrWhiteSpace(answer))
            {
                results.Add($"[Answer] {answer}");
            }

            return results.Count > 0
                ? string.Join("\n\n", results)
                : $"No detailed results found for '{query}'. Try rephrasing your search or breaking it into smaller queries.";
        }
        catch (Exception ex) when (ex is HttpRequestException or TaskCanceledException or JsonException)
        {
            return $"Search failed for '{query}': {ex.Message}. Try a different query.";
        }
    }

    [Description("Saves a research note with a key finding or insight. Use this to record important information discovered during research.")]
    private string SaveNote(
        [Description("The note text to save — should be a concise finding or insight")] string note)
    {
        _notes.Add(note);
        return $"Note #{_notes.Count} saved successfully.";
    }

    [Description("Retrieves all previously saved research notes. Use this to review what has been learned so far before writing a summary.")]
    private string GetNotes()
    {
        if (_notes.Count == 0)
        {
            return "No notes saved yet.";
        }

        return string.Join("\n", _notes.Select((n, i) => $"Note #{i + 1}: {n}"));
    }
}

