 // Build the research agent with instructions and tools.
 var agent = new ChatClientAgent(
     chatClient,
     instructions: """
         You are a research agent. Your job is to research a topic thoroughly by:
         1. Searching the web multiple times with different queries to gather diverse information.
         2. Saving key findings as notes using the save_note tool.
         3. Reviewing your notes with get_notes before writing the final summary.
         4. Producing a well-structured summary of your research findings.

         Always perform at least 3 different searches to get broad coverage of the topic.
         Save important facts, statistics, and insights as notes as you discover them.
         When you have gathered enough information, review your notes and write a comprehensive summary.
         """,
     name: "ResearchAgent",
     description: "An agent that researches topics by searching the web and summarizing findings.",
     tools: tools);

 // Prompt the user for a research topic.
 Console.Write("Enter a research topic: ");
 var topic = Console.ReadLine()?.Trim();

 if (string.IsNullOrWhiteSpace(topic))
 {
     Console.Error.WriteLine("No topic provided. Exiting.");
     return;
 }

 Console.WriteLine();
 Console.WriteLine($"Researching: {topic}");
 Console.WriteLine(new string('-', 50));
 Console.WriteLine();

 // Run the agent with streaming output.
 var messages = new List<ChatMessage>
 {
     new(ChatRole.User, $"Research the following topic and provide a comprehensive summary: {topic}"),
 };

 var session = await agent.CreateSessionAsync(topic);

 var runOptions = new ChatClientAgentRunOptions(new ChatOptions
 {
     Temperature = 0f,
     MaxOutputTokens = 2048,
 });

 await foreach (var update in agent.RunStreamingAsync(messages, session, runOptions))
 {
     Console.Write(update.Text);
 }

 Console.WriteLine();
 Console.WriteLine();
 Console.WriteLine(new string('=', 50));
 Console.WriteLine($"Research complete. {researchTools.Notes.Count} note(s) saved during research.");
